import React, { useState } from "react";
import AddIcon from '@mui/icons-material/Add';
import Fab from '@mui/material/Fab';
import Zoom from '@mui/material/Zoom';

function CreateArea(props) {
  const [note, setNote] = useState({ title: '', content: '', color: '#ffffff' })
  const [click, setClick] = useState(false)

  const handleChange = (event) => {
    const { name, value } = event.target
    setNote(pv => {
      return { ...pv, [name]: value }
    })
  }
  const handleclick = () => {
    setClick(true)
  }
  return (
    <div>
      <form onSubmit={event => { event.preventDefault() }} className="create-note" style={{ backgroundColor: note.color }}>
        {click && (
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <input onChange={handleChange} name="title" placeholder="Title" value={note.title} style={{ backgroundColor: 'transparent', flex: 1 }} />
            <input 
              title="Pick note color"
              onChange={handleChange} 
              type="color" 
              name="color" 
              value={note.color}
              style={{ padding: 0, width: '25px', height: '25px', border: 'none', cursor: 'pointer', backgroundColor: 'transparent' }} 
            />
          </div>
        )}
        <textarea onClick={handleclick} onChange={handleChange} name="content" placeholder="Take a note..." rows={click ? '3' : '1'} value={note.content} style={{ backgroundColor: 'transparent' }} />
        <Zoom in={click}>
          <Fab onClick={() => {
            if (note.content.trim() !== '') {
              props.addContent(note)
              setNote({ title: '', content: '', color: '#ffffff' })
            }
          }}><AddIcon /></Fab>
        </Zoom>
      </form>
    </div>
  );
}

export default CreateArea;
